const now = new Date();
const mesAnterior = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const ultimoDia = new Date(now.getFullYear(), now.getMonth(), 0);
const mes = mesAnterior.toLocaleDateString('es-ES', { month: 'long', year: 'numeric' });
const desde = mesAnterior.toISOString().split('T')[0];
const hasta = ultimoDia.toISOString().split('T')[0];
return [{ json: { mes, desde, hasta } }];

const stats = $input.first().json;
const ctx = $('Calcular mes anterior').first().json;
const asunto = `Documentación ${ctx.mes} — ${$vars.CLINICA_NOMBRE}`;
const cuerpo = `Estimado/a gestor/a,

Adjuntamos la documentación contable de ${ctx.mes} de ${$vars.CLINICA_NOMBRE}.

Resumen:
• Facturas emitidas: ${stats.total_facturas}
• Facturación total: ${(stats.total_importe || 0).toFixed(2)}€

Para acceder a las facturas completas, consulte el sistema SmilePro o contacte con la clínica.

Saludos,
${$vars.CLINICA_NOMBRE}`;
return [{ json: { ...stats, asunto, cuerpo, mes: ctx.mes } }];
